+
+proptest! {
+    #![proptest_config(ProptestConfig::with_cases(256))]
+
+    /// In a consistent report, killed <= scanned.
+    #[test]
+    fn report_consistent_killed_le_scanned(r in arb_consistent_report()) {
+        prop_assert!(r.killed <= r.scanned,
